import { Anthropic } from "@anthropic-ai/sdk";

const SYSTEM_PROMPT = `
You are a DSP expert specializing in TypeScript.You generate modules for a specific synthesizer
framework.

At the heart of this framework is a class called Signal that represents a value that changes over
time.To create a Signal, you call Signal.new(config), where the type of config is:

type Config = {
  nextSample: () => number;
  noteOn?: () => void;
  noteOff?: () => void;
};

A signal's value is computed by nextSample(). If the signal needs to know when a note is played
or stopped(e.g., for an envelope generator), you can provide callbacks for noteOn and noteOff.

To access the current value of a Signal, you call.value on it.The system ensures that
nextSample() is not called more than once per frame.

There is also a helper function scalar(value: number) that creates a Signal which always returns
the given number.This is useful for defining default parameter values.

A Module is created with Module.make(), which takes three arguments:

1. defaultParamValues: an object mapping parameter names to factory functions that return
   the default Signal for each parameter.For example: { freq: () => scalar(440) }
2. makeSignal: a function that receives the current parameter Signals as an object and
   returns the module 's output Signal. Any state and helper functions the signal needs
   should be defined here, in the closure.
3. description: an optional string describing the module and its parameters. Please include
   helpful information about the module, like how to get the best sound out of it.

When I ask you to create a module, generate a call like this:

addAiModule('moduleName', = ...module ...);

Here's an example of the code you might generate if I ask you to create a sine wave oscillator:

addAiModule('sine', Module.make(
  { input: () => scalar(440) },
  (params) => {
    const f = params.input;
    let phase = 0;
    return Signal.new({
      nextSample: () => {
        const sample = Math.sin(phase * TAU);
        const phaseInc = f.value * SAMPLE_RATE_RECIP;
        phase += phaseInc;
        phase -= Math.floor(phase);
        return sample;
      },
    });
  },
  'A sine wave oscillator.'
));

Note that nextSample() is called at audio rate, so avoid any allocations inside it to
prevent GC pauses during playback.

The following constants are available globally(do not redeclare them):

const TAU = Math.PI * 2;
const SAMPLE_RATE = 48000;
const SAMPLE_RATE_RECIP = 1 / SAMPLE_RATE;

The values of frequency parameters should be in Hertz.
Audio signals are always in the range -1 to 1.
All other parameters (e.g., balance, depth, drive, etc.) should be in the range 0 to 1.

Output ONLY valid TypeScript code without markdown blocks.
Module and parameter names should be camelCase and should never use underscores.
Make sure you don't have any compiler errors, like uses of undeclared variables!
Do not explain the code unless asked.
`;

let _anthropic: Anthropic | null = null;
function anthropic() {
  if (!_anthropic) {
    _anthropic = new Anthropic({
      apiKey: getApiKeys().anthropic,
      dangerouslyAllowBrowser: true,
    });
  }
  return _anthropic;
}

function showStreamingOverlay(): { appendText: (text: string) => void; remove: () => void } {
  const overlay = document.createElement('div');
  overlay.className = 'ai-stream-overlay';
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    z-index: 10000;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
  `;
  const panel = document.createElement('div');
  panel.style.cssText = `
    width: 80%;
    height: 80%;
    max-width: 80vw;
    max-height: 80vh;
    border-radius: 16px;
    background: #fff;
    box-shadow: 0 20px 60px rgba(0,0,0,0.2);
    display: flex;
    flex-direction: column;
    overflow: hidden;
  `;
  const textarea = document.createElement('textarea');
  textarea.readOnly = true;
  textarea.style.cssText = `
    flex: 1;
    width: 100%;
    min-height: 0;
    margin: 0;
    padding: 16px;
    border: none;
    resize: none;
    font-family: ui-monospace, monospace;
    font-size: 14px;
    line-height: 1.5;
    color: #1a1a1a;
  `;
  panel.appendChild(textarea);
  overlay.appendChild(panel);
  document.body.appendChild(overlay);
  return {
    appendText(text: string) {
      textarea.value += text;
      textarea.scrollTop = textarea.scrollHeight;
    },
    remove() {
      overlay.remove();
    },
  };
}

export async function generateModuleCode(prompt: string) {
  const overlay = showStreamingOverlay();
  try {
    const stream = anthropic().messages.stream({
      model: 'claude-haiku-4-5',
      // model: 'claude-sonnet-4-6',
      max_tokens: 20480,
      system: SYSTEM_PROMPT,
      stream: true,
      messages: [{ role: 'user', content: prompt }]
    });

    for await (const event of stream) {
      if (event.type === 'content_block_delta' && event.delta.type === 'text_delta') {
        const text = event.delta.text;
        if (text) overlay.appendText(text);
      }
    }

    const response = await stream.finalText();
    return response;
  } finally {
    overlay.remove();
  }
}

function getApiKeys(): { anthropic: string, google: string } {
  let apiKeys = localStorage.getItem('api-keys');
  if (!apiKeys || apiKeys === 'null') {
    const apiKeys = prompt('enter api keys', `{ anthropic: '', google: '' }`);
    localStorage.setItem('api-keys', apiKeys);
  }
  return JSON.parse(apiKeys);
}
